import math

def minCost(costs: list[list[int]]) -> int:
    n = len(costs)
    if n == 0:
        return 0

    k = len(costs[0])
    if k == 0:
        return 0

    current_costs = list(costs[0])

    for i in range(1, n):
        prev_min1 = math.inf
        prev_idx1 = -1
        prev_min2 = math.inf

        for j in range(k):
            if current_costs[j] < prev_min1:
                prev_min2 = prev_min1
                prev_min1 = current_costs[j]
                prev_idx1 = j
            elif current_costs[j] < prev_min2:
                prev_min2 = current_costs[j]

        next_costs = [0] * k
        for j in range(k):
            if j == prev_idx1:
                next_costs[j] = costs[i][j] + prev_min2
            else:
                next_costs[j] = costs[i][j] + prev_min1

        current_costs = next_costs

    return min(current_costs)
